    suspend fun getCurrentUser(): Response<ApiResponse<UserProfile>>

    @POST("users")
    suspend fun createUser(
        @Body userProfile: UserProfile
    ): Response<ApiResponse<UserProfile>>

    @PATCH("users/{id}")
    suspend fun updateUser(
        @Path("id") userId: Long,
        @Body updates: Map<String, Any>
    ): Response<ApiResponse<UserProfile>>

    @DELETE("users/{id}")
    suspend fun deleteUser(
        @Path("id") userId: Long
    ): Response<ApiResponse<Unit>>

    @GET("users/search")
    suspend fun searchUsers(
        @Query("q") query: String,
        @Query("page") page: Int = 1,
        @Query("per_page") perPage: Int = 20
    ): Response<PaginatedResponse<UserProfile>>
}

// File: network/NetworkResult.kt
package com.example.app.network

sealed class NetworkResult<out T> {
    data class Success<out T>(val data: T) : NetworkResult<T>()
    data class Error(val code: Int, val message: String?) : NetworkResult<Nothing>()
    data class Exception(val throwable: Throwable) : NetworkResult<Nothing>()

    val isSuccess get() = this is Success
    val isError get() = this is Error
    val isException get() = this is Exception

    fun getOrNull(): T? = when (this) {
        is Success -> data
        else -> null
    }

    fun <R> map(transform: (T) -> R): NetworkResult<R> = when (this) {
        is Success -> Success(transform(data))
        is Error -> this
        is Exception -> this
    }
}

// File: network/SafeApiCall.kt
package com.example.app.network

import retrofit2.Response

suspend fun <T> safeApiCall(apiCall: suspend () -> Response<T>): NetworkResult<T> {
    return try {
        val response = apiCall()
        if (response.isSuccessful) {
            val body = response.body()
            if (body != null) {
                NetworkResult.Success(body)
            } else {
                NetworkResult.Error(response.code(), "Response body is null")
            }
        } else {
            NetworkResult.Error(response.code(), response.errorBody()?.string())
        }
    } catch (e: java.io.IOException) {
        NetworkResult.Exception(e)
    } catch (e: kotlin.Exception) {
        NetworkResult.Exception(e)
    }
}

// File: network/NetworkModule.kt
package com.example.app.network

import com.example.app.network.api.UserApiService
import com.google.gson.GsonBuilder
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private var environment: Environment = Environment.DEV
    private var tokenProvider: TokenProvider = InMemoryTokenProvider()
    private var retrofit: Retrofit? = null
    private var okHttpClient: OkHttpClient? = null

    fun init(
        environment: Environment,
        tokenProvider: TokenProvider = InMemoryTokenProvider()
    ) {
        this.environment = environment
        this.tokenProvider = tokenProvider
        this.retrofit = null
        this.okHttpClient = null
    }

    fun setEnvironment(env: Environment) {
        this.environment = env
        this.retrofit = null
        this.okHttpClient = null
    }

    fun getTokenProvider(): TokenProvider = tokenProvider

    private fun buildOkHttpClient(): OkHttpClient {
        if (okHttpClient != null) return okHttpClient!!

        val loggingInterceptor = HttpLoggingInterceptor().apply {
            level = when (environment) {
                Environment.DEV -> HttpLoggingInterceptor.Level.BODY
                Environment.STAGING -> HttpLoggingInterceptor.Level.HEADERS
                Environment.PRODUCTION -> HttpLoggingInterceptor.Level.NONE
            }
        }

        okHttpClient = OkHttpClient.Builder()
            .addInterceptor(AuthInterceptor(tokenProvider))
            .addInterceptor(loggingInterceptor)
            .authenticator(TokenAuthenticator(tokenProvider))
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .retryOnConnectionFailure(true)
            .build()

        return okHttpClient!!
    }

    private fun buildRetrofit(): Retrofit {
        if (retrofit != null) return retrofit!!

        val gson = GsonBuilder()
            .setLenient()
            .create()

        retrofit = Retrofit.Builder()
            .baseUrl(environment.baseUrl)
            .client(buildOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create(gson))
            .build()

        return retrofit!!
    }

    val userApiService: UserApiService by lazy(LazyThreadSafetyMode.SYNCHRONIZED) {
        buildRetrofit().create(UserApiService::class.java)
    }

    fun <T> createService(serviceClass: Class<T>): T {
        return buildRetrofit().create(serviceClass)
    }
}

